const retest = $('Get Retest Record').first().json;
const input = $('Execute Workflow Trigger').first()?.json || $('Webhook').first()?.json?.body || {};
const inputData = input.body || input;
return [{ json: {
  retest_id: retest.retest_id,
  finding_id: retest.finding_id,
  engagement_id: retest.engagement_id,
  severity: retest.severity,
  reopen_count: parseInt(retest.reopen_count || 0),
  result: inputData.result,
  retest_evidence: inputData.retest_evidence || '',
  retested_by: inputData.retested_by || 'analyst',
  notes: inputData.notes || ''
} }];
